class Solution:
    def projectMissingFields(self, document: dict) -> dict:
        def recursiveProject(document):
            projected_document = {}
            for field, value in document.items():
                if isinstance(value, dict):
                    projected_document[field] = recursiveProject(value)
                elif value is not None:
                    projected_document[field] = value
            return projected_document
        return recursiveProject(document)
